import { unProxy as unproxyXhr, proxy as proxyXhr } from 'ajax-hook';
import { RequestConfig, ResponseConfig } from './types';
import { proxyFetch, unproxyFetch } from './fetch';

export interface NetProxyOptions {
    enableScope?: EnableScope[];

    beforeRequest?(config: RequestConfig): Promise<RequestConfig>;

    afterResponse?(config: ResponseConfig): Promise<ResponseConfig>;
}

export enum EnableScope {
    FETCH = 'fetch',
    XHR = 'xhr',
}

const _enabledScope: Set<EnableScope> = new Set([]);

export function proxy({
    enableScope = Object.values(EnableScope),
    beforeRequest,
    afterResponse,
}: NetProxyOptions) {
    if (enableScope.includes(EnableScope.XHR)) {
        proxyXhr({
            onRequest(config, handler) {
                beforeRequest &&
                    beforeRequest(config).then((overrideConfig) => {
                        handler.next({
                            ...config,
                            ...overrideConfig,
                        });
                    });
            },
            onResponse(config, handler) {
                afterResponse &&
                    afterResponse(config).then((overrideConfig) => {
                        handler.next({
                            ...config,
                            ...overrideConfig,
                        });
                    });
            },
        });
    }
    if (enableScope.includes(EnableScope.FETCH)) {
        proxyFetch({
            async onRequest(info, init) {
                if (beforeRequest) {
                    const r = new Request(info, init);
                    const config = await beforeRequest({
                        url: r.url,
                        method: r.method,
                        // @ts-ignore
                        headers: r.headers ? Object.fromEntries(r.headers): undefined,
                    });
                    return [new Request(r, config)];
                }

                return [info, init];
            },
            async onResponse(response) {
                if (afterResponse) {
                    afterResponse({
                        status: response.status,
                        statusText: response.statusText,
                        response,
                        config: {
                            url: response.url,
                        },
                    });
                }
                return response;
            },
        });
    }
}

export function unproxy() {
    if (_enabledScope.has(EnableScope.XHR)) {
        unproxyXhr();
    }
    if (_enabledScope.has(EnableScope.FETCH)) {
        unproxyFetch();
    }
}
